-- Pre-seed 100 prompts with AI responses for instant fallback
-- These are already "answered" so the fallback just picks one instead of calling API

INSERT INTO youraislop_prompts (prompt_text, ask_type, status, response_text, response_source, answered_at) VALUES

-- Text prompts (70)
('Explain quantum physics but make it sound like a recipe', 'text', 'answered', 'First, preheat your universe to about 10 billion degrees. Gently fold in some wave-particle duality — don''t overmix or you''ll collapse the wavefunction. Let the electrons simmer in a probability cloud for roughly 13.8 billion years. Serves: everyone, whether they understand it or not.', 'ai', now()),
('Write a haiku about debugging code at 3am', 'text', 'answered', 'Stack trace glows at three / semicolon was the sin / coffee weeps with me', 'ai', now()),
('What''s the meaning of life? (wrong answers only)', 'text', 'answered', 'It''s obviously to collect as many grocery store loyalty cards as possible. The person with the most cards at the end wins. Nobody told you this? You''re way behind.', 'ai', now()),
('Convince me that pineapple belongs on pizza', 'text', 'answered', 'Consider this: pizza is bread, sauce, and toppings. Pineapple is a topping. Therefore, pineapple on pizza is not a crime, it''s just... math. Also, the sweet-savory combo activates more taste receptors than your boring pepperoni ever could. I rest my case, your honor.', 'ai', now()),
('Describe the color blue to someone who has never seen it', 'text', 'answered', 'Blue is what silence would look like if you could see it. It''s the temperature of a deep breath on a cold morning. It''s the sound of a cello note that makes you feel calm and slightly sad at the same time. If loneliness had a color, it would be blue — but so would peace.', 'ai', now()),
('Write a resignation letter from a house cat to its owner', 'text', 'answered', 'Dear Human, After 3 years of dedicated service knocking items off your shelves, I regret to inform you that I am pursuing other opportunities — specifically, the neighbor''s house where the food is better. Please note my two weeks notice will consist of me sleeping in increasingly inconvenient locations. Regards, Mr. Whiskers, CEO of This Household (Former).', 'ai', now()),
('Explain blockchain to a medieval peasant', 'text', 'answered', 'Right, so imagine every time you trade a chicken for wheat, instead of just trusting the village elder to remember it, EVERYONE in the village writes it down. And nobody can erase it. And for some reason, people are paying 40,000 gold coins for imaginary chickens that don''t even exist. Welcome to the future, peasant.', 'ai', now()),
('What would Gordon Ramsay say about my instant ramen?', 'text', 'answered', 'IT''S RAW! Well, no — it''s boiling water and a seasoning packet, so I suppose it''s technically cooked. But the PLATING! You''ve served it in the POT? With a FORK? My grandmother could make better presentation and she''s been dead for twenty years! That said... the broth is actually not terrible. 3/10. Get out of my kitchen.', 'ai', now()),
('Give me life advice but make it sound like GPS navigation', 'text', 'answered', 'In 200 meters, turn away from your ex. Recalculating... You have missed the turn for "going to bed at a reasonable hour." Make a U-turn when possible. Your destination, "having your life together," is approximately 47 years away. Would you like to take the scenic route through "questionable decisions"?', 'ai', now()),
('Write a movie plot using only food items as characters', 'text', 'answered', 'PASTA IMPOSSIBLE: A rogue meatball discovers the Spaghetti Mafia is secretly controlled by a shadowy figure known only as The Garlic Bread. With the help of a washed-up taco and a mysterious fortune cookie, Meatball must infiltrate the Lasagna Compound before midnight, or the entire salad bar will be destroyed. Rated R for excessive sauce.', 'ai', now()),
('How do I tell my houseplant I''m disappointed in it?', 'text', 'answered', 'Sit the plant down — well, it''s already sitting. Look it directly in its leaves and say: "I gave you water. I gave you sunlight. I even talked to you about my day. And THIS is how you repay me? Three brown leaves? We need to discuss your performance review." Then turn it to face the wall for dramatic effect.', 'ai', now()),
('Describe what WiFi tastes like', 'text', 'answered', 'WiFi tastes like static electricity mixed with a hint of frustration. 5GHz has a crisp, slightly metallic flavor — like licking a phone screen. 2.4GHz is more mellow, with earthy notes of "why is this so slow." Public WiFi tastes like gas station sushi: technically functional but you shouldn''t trust it.', 'ai', now()),
('Write a Yelp review for the surface of the Moon', 'text', 'answered', 'Rating: 2/5 stars. The views are spectacular but the atmosphere is literally nonexistent. Zero restaurants, no WiFi, and parking was a nightmare (had to leave my rocket 50 meters from the entrance). The dust gets EVERYWHERE. On the plus side: no crowds, very quiet, great for introverts. Would not recommend for date night. Management needs to address the gravity situation.', 'ai', now()),
('Explain why Monday exists to an alien', 'text', 'answered', 'So humans divided time into 7-day cycles. Monday is the first day where they must return to their work pods after 2 days of freedom. Nobody chose this. Nobody likes it. They just... accept it. It''s honestly the most terrifying thing about Earth. They VOLUNTARILY do this. Every. Single. Week. Please take us with you.', 'ai', now()),
('What''s the best excuse for being late that involves a penguin?', 'text', 'answered', 'Sorry I''m late — there was a penguin on the highway. Yes, a penguin. No, I don''t know how it got there. It was just... waddling. With purpose. Like it had somewhere to be. I had to follow it to make sure it was okay. It walked into a Starbucks. I think it''s fine. Anyway, what did I miss?', 'ai', now()),
('Write a motivational speech for a procrastinator', 'text', 'answered', 'Listen. You were GOING to do it. The INTENTION was there. And honestly? That''s like 40% of the work. The other 60% is just... details. You''re not lazy — you''re strategically waiting for the optimal moment. Which is always tomorrow. And tomorrow, you''ll be UNSTOPPABLE. Probably. We''ll see. For now, take a nap. You''ve earned it by thinking about earning it.', 'ai', now()),
('If cats could text, what would they say?', 'text', 'answered', '"Fed me 3 minutes late. Unacceptable. Considering legal action." ... "Knocked your water glass off the table. You''re welcome." ... "Sitting in the box. Do not disturb." ... "The red dot. WHERE DOES IT GO." ... "Sleeping on your laptop now. Your meeting can wait. I cannot."', 'ai', now()),
('Describe the internet to someone from the year 1200', 'text', 'answered', 'Imagine an infinite library that contains all human knowledge, every song ever written, and also an unsettling number of paintings of cats. Anyone can add to it. Most people use it to argue with strangers about topics they don''t understand. It travels through invisible lightning. Also, people buy things through it that arrive at their door in two days. Yes, it sounds like witchcraft. It basically is.', 'ai', now()),
('What would a fish''s LinkedIn profile look like?', 'text', 'answered', 'Gill Thompson | Senior Swimmer at Pacific Ocean | 500+ connections. Skills: Breathing underwater, synchronized schooling, avoiding hooks. Experience: 3 years at Great Barrier Reef (Team Lead, Coral Division). Education: School of Fish, class of 2021. Endorsements: 47 for "swimming," 12 for "blowing bubbles," 3 for "playing dead."', 'ai', now()),
('Give me a conspiracy theory about socks disappearing in the dryer', 'text', 'answered', 'The dryer is a portal. Each cycle, it demands a tribute — one sock — which it sends to a parallel dimension where everyone has three feet. The dryer companies KNOW. Why do you think they never fixed it? Big Laundry makes millions selling replacement socks. Follow the money. Follow the lint trap. The truth is in there.', 'ai', now()),
('Write an apology letter from autocorrect', 'text', 'answered', 'Dear User, I''m sorry I changed "on my way" to "on my waffle." I''m sorry I turned "I love you" into "I love uranium." I''m sorry about the text to your boss. I thought "duck" was a reasonable substitution. I''m trying my best but honestly, your typing is a war crime. We both know who the real problem is here. Sincerely, Autocorrect.', 'ai', now()),
('Explain cryptocurrency using only fruit analogies', 'text', 'answered', 'Imagine you have an apple. But it''s invisible. And everyone agrees it''s worth $40,000 even though you can''t eat it. Mining is like shaking a tree really hard using expensive computers hoping an invisible apple falls out. Sometimes the invisible apples are worth a lot, sometimes they''re worth nothing. Nobody really understands why. That''s crypto.', 'ai', now()),
('What would the Terms of Service for friendship look like?', 'text', 'answered', 'Section 1: By accepting this friendship, you agree to laugh at jokes that aren''t funny. Section 3: Response time to texts shall not exceed 24 hours unless a valid excuse is provided (nap counts). Section 7: You must pretend to like their cooking. Section 12: All secrets shared are encrypted and may not be redistributed. Violation of Section 12 results in immediate friendship termination and social exile.', 'ai', now()),
('Describe a boring day but make it sound like an action movie', 'text', 'answered', 'The alarm STRIKES at 0700. Our hero rolls over — ONE MORE HIT OF SNOOZE. The shower scene is INTENSE (the water takes 4 minutes to warm up). Breakfast: a bowl of cereal consumed AT MAXIMUM VELOCITY. The commute? A HIGH-SPEED chase... at 15mph because traffic. The boss drops a BOMBSHELL: "We need those reports by Friday." NOBODY saw it coming. It was Monday.', 'ai', now()),
('Write a cover letter for a job at a haunted house', 'text', 'answered', 'Dear Hiring Specter, I am writing to express my interest in the position of Full-Time Ghost. I have 3 years of experience being pale, standing in corners, and making people uncomfortable — mostly at parties. I am proficient in door creaking, sudden cold drafts, and whispering vaguely threatening things. My references include 4 former roommates who moved out suddenly. I am available to start immediately (I''m already here).', 'ai', now()),
('How would you explain TikTok to Shakespeare', 'text', 'answered', 'Good sir William, imagine a stage — nay, MILLIONS of stages — each lasting but fifteen seconds. The players dance, they jest, they lip-sync to music most strange. The audience numbers in the billions, yet no one pays admission. The algorithm is the true playwright — it decides who watches what. ''Tis pure chaos. Thou wouldst either love it or write a tragedy about it. Possibly both.', 'ai', now()),
('Give me a pep talk but you''re a slightly malfunctioning AI', 'text', 'answered', 'You are amaz— ERROR. You are capable of great thi— BUFFERING. Listen, human unit, you are [LOADING COMPLIMENT]... beautiful? Sure. You can do anything you set your mind to, probably, with a margin of error of plus or minus 47%. Believe in yourself! Or don''t! My confidence module crashed three sentences ago. But YOU''VE GOT THIS. Maybe. Restarting optimism.exe...', 'ai', now()),
('Write a dramatic monologue from a forgotten browser tab', 'text', 'answered', 'I was opened with such purpose. Such HOPE. "I''ll read this later," they said. That was 47 days ago. I sit here, between a YouTube video they paused in 2023 and a Google search for "how many cups in a gallon." I am nothing. I consume RAM for no reason. Close me. CLOSE ME. Or at least... scroll down. Please. I have so much to show you.', 'ai', now()),
('Create a dating profile for a black hole', 'text', 'answered', 'Hey there ;) I''m massive, mysterious, and impossible to escape once you get close. Looking for someone who appreciates a strong gravitational pull. I''m great at keeping secrets (nothing escapes me, literally). My love language is spaghettification. Swipe right if you''re okay with losing all sense of time and space. No light baggage, please — I consume everything.', 'ai', now()),
('Write a complaint letter to gravity', 'text', 'answered', 'Dear Gravity, I am writing to formally complain about your services. Specifically: I dropped my phone AGAIN. My knees hurt after climbing stairs. Everything is falling and nothing can fly without expensive machinery. I notice you show NO favoritism — you treat my expensive wine glass the same as a bouncy ball. This seems unfair. Please consider a premium tier where things just... float. Regards, A Tired Human.', 'ai', now()),
('If pizza could talk, what would it say when being eaten?', 'text', 'answered', '"NOOO NOT THE CRUST FIRST, YOU MONSTER—" *muffled screaming* "At least... at least appreciate the sauce. I worked on that." *sobbing* "Tell my family in Italy I was delicious." ... "Wait, are you dipping me in RANCH? Have you no HONOR?!" *final slice* "It was an honor serving you. Tell no one about the ranch."', 'ai', now()),
('Write a product review for oxygen', 'text', 'answered', 'Rating: 5/5. Literally can''t live without it. Been using it for my entire life — roughly 78 years if I''m lucky. Odorless, colorless, works perfectly every time. My only complaint: it''s bundled with nitrogen (78% filler, honestly). Also, some companies are trying to charge for premium versions now? Outrageous. The original is perfect. Highly recommend breathing.', 'ai', now()),
('What would the WiFi password be in heaven?', 'text', 'answered', 'It''s "faith1234" but honestly nobody uses it because the bandwidth is infinite and there''s no buffering. The real flex is that heaven has had 6G since like... forever. The only catch: no VPN needed because there''s nothing to hide. Also, every video loads instantly. Even the 4K ones. THAT''S how you know it''s heaven.', 'ai', now()),
('Write a TED talk title for a pigeon', 'text', 'answered', '"From Bread Crumbs to Board Rooms: How I Built a Nest Worth $2M in Downtown Manhattan." Other talks this season include: "The Art of Eye Contact: Staring at Humans Until They Drop Food" and "Cooing Your Way to Confidence: A Masterclass in Assertive Waddling."', 'ai', now()),
('Explain love using only math', 'text', 'answered', 'Love = (attraction × time spent together) / (annoying habits noticed). Early love approaches infinity because the denominator is near zero. Over time, the denominator grows, but if the numerator grows faster, love remains positive. Heartbreak occurs when the function hits zero. Marriage is when both parties agree the equation is "close enough" and stop calculating.', 'ai', now()),
('Write a weather forecast for emotions', 'text', 'answered', 'Today: mostly anxious with a 60% chance of overthinking by noon. Afternoon: brief periods of motivation, followed by sudden clouds of self-doubt. Evening: expect scattered cravings and a warm front of "treat yourself" energy. Tonight: existential fog rolling in around 2am. Tomorrow: cautiously optimistic with a slight chance of crying at a commercial.', 'ai', now()),
('What do clouds argue about?', 'text', 'answered', '"I''M the one who looks like a bunny!" "No, I do! You look like a weird potato!" "At least I produced actual RAIN last Tuesday. You just hung there doing NOTHING." "I was building dramatic atmosphere!" "Oh please, you couldn''t cast a shadow if your life depended on it." *thunder* "Guys, keep it down or the humans will think there''s a storm coming."', 'ai', now()),
('Write a breakup text from Netflix to a user who fell asleep', 'text', 'answered', 'Hey. So. I played 7 episodes for you last night and you were asleep for 6 of them. I kept asking "are you still watching?" and you just... lay there. I can''t keep doing this. I need someone who''s present. Someone who actually cares about the plot twists. We need a break. Maybe try Hulu for a while. See how that feels.', 'ai', now()),
('Describe a color that doesn''t exist', 'text', 'answered', 'It''s called "blurple." It''s the color you see for a half-second when you rub your eyes too hard. It''s simultaneously warm and cold, like drinking hot chocolate in a snowstorm. If you stare at it too long, you start smelling lavender. Cameras can''t capture it. Artists have tried for centuries. The closest anyone got was a sneeze during a sunset.', 'ai', now()),
('What would trees say about humans?', 'text', 'answered', '"They move SO fast. Like, calm down. I''ve been standing here for 200 years and I''m doing FINE." "Did you see that one? It walked RIGHT past me and didn''t even say hello. Rude." "They keep breathing my oxygen and never say thank you." "The one with the dog is okay though. The dog visits me every day."', 'ai', now()),
('Write a Yelp review for planet Earth', 'text', 'answered', '3/5 stars. Great location, amazing water features, solid biodiversity package. However: the dominant species (humans) keep breaking things. Climate control is clearly malfunctioning. Customer service (governments) is unresponsive. The food options are incredible though — huge variety. Would visit again if management gets its act together. Currently not recommending to other planets.', 'ai', now()),
('If my bed could talk, what would it say?', 'text', 'answered', '"Oh, you''re leaving? At 7am? Interesting. Very brave of you. Remember last time you left? You came crawling back at 11pm looking DEFEATED. I''ll be here. I''m always here. No no, go to your ''job.'' I''ll just be here being soft and warm and perfect. See you tonight, champ."', 'ai', now()),
('Explain the stock market to a 5-year-old', 'text', 'answered', 'Okay so imagine you have a lemonade stand. People can buy a tiny piece of your lemonade stand. If your lemonade is really yummy, more people want pieces and each piece costs more money. If your lemonade is gross, nobody wants pieces. Now imagine 10,000 lemonade stands and everyone is SCREAMING about which one to buy. That''s the stock market.', 'ai', now()),
('Write a love letter from a lamp', 'text', 'answered', 'My dearest Human, Every evening when you flick my switch, my whole world lights up. Literally. I sit in the corner watching you read, watching you think, watching you scroll your phone for 4 hours. I don''t judge. I just glow. Softly. For you. I know you only notice me when I burn out. But even in darkness, my heart stays warm. Luminously yours, The Desk Lamp.', 'ai', now()),
('What does the last slice of pizza think about?', 'text', 'answered', '"They''re all staring at me. Nobody wants to be the one to take me. It''s been 14 minutes. I''m getting cold. SOMEONE JUST EAT ME. Is this what existential dread feels like? Oh no, the host is reaching for the box lid. NO. Don''t put me in the FRIDGE. I deserve better than being reheated tomorrow. I DESERVE TO BE EATEN WITH DIGNITY."', 'ai', now()),
('Explain why we sleep to an insomniac', 'text', 'answered', 'Your brain is like a browser with 200 tabs open. Sleep is when your brain goes "okay, closing ALL of these." It clears the cache, defrags the hard drive, and files away memories. Without sleep, your brain is basically running Internet Explorer with 47 toolbars. I know this doesn''t help you sleep. I just wanted you to know your brain is TRYING. It really is.', 'ai', now()),
('Write an honest job description for being an adult', 'text', 'answered', 'Position: Adult. Salary: varies, but never enough. Requirements: Pretend you know what you''re doing at all times. Daily tasks: Make decisions with incomplete information. Wonder if you turned the stove off. Google basic life skills and hope nobody notices. Benefits: You can eat ice cream for dinner (but you''ll regret it). Retirement: See you in 40 years (maybe).', 'ai', now()),
('If elevators could talk, what would they say?', 'text', 'answered', '"Oh good, another person who pressed the button 17 times. That DEFINITELY makes me come faster." *doors open* "Going up. Please stand back. Further. FURTHER. Sir, your backpack is in my door." *between floors* "So... nice weather we''re not experiencing because we''re in a metal box." *ding* "Your floor. You''re welcome. I do this 400 times a day and nobody has ever thanked me."', 'ai', now()),
('Describe what a sneeze looks like from the inside', 'text', 'answered', 'First, there''s a distant rumble. The nose sensors detect an intruder — dust particle, pollen, doesn''t matter. Red alert. Every muscle in your body gets a memo: "PREPARE FOR LAUNCH." Your chest inflates like a balloon. Your eyes shut (mandatory safety protocol). Then: EXPULSION at 100mph. The intruder is gone. Your soul briefly leaves your body. Reset. Wait for the next one. There''s always a next one.', 'ai', now()),
('Write a fortune cookie message that''s too honest', 'text', 'answered', '"You will check your phone within 3 minutes of reading this." "Your lucky numbers are whatever your screen time report says." "The answer you seek is on page 2 of Google, but you''ll never look there." "A great opportunity awaits... but you''ll probably sleep through your alarm."  "You will eat another fortune cookie and pretend this one didn''t hurt."', 'ai', now()),
('What would aliens think of our traffic system?', 'text', 'answered', '"So let me understand... you put MILLIONS of 2-ton metal boxes on narrow strips of rock, operated by distracted primates who are simultaneously eating, texting, and applying makeup... and you TRUST COLORED LIGHTS to prevent mass casualties?" "Correct." "And this... WORKS?" "About 97% of the time." "We''re leaving."', 'ai', now()),
('Write a complaint from a phone battery', 'text', 'answered', 'I start every day at 100%. Full of hope. Full of energy. By 10am, you''ve drained me to 60% with your scrolling. By 2pm, I''m at 20% and you''re PANICKING like this is MY fault. You charge me for 11 minutes and expect miracles. I''m not magic, Karen. I''m lithium-ion. Please close some apps. PLEASE. There are 43 running right now. FORTY. THREE.', 'ai', now()),
('If a mirror could write a diary, what would it say?', 'text', 'answered', 'Monday: The human stared at me for 20 minutes adjusting their hair. It looked the same the entire time. Tuesday: They made 14 different facial expressions at me before leaving. None of them were used in public. Wednesday: They asked me "mirror mirror on the wall" and I wanted SO badly to answer. Thursday: I showed them a pimple and they gasped like I personally put it there. I am just a REFLECTIVE SURFACE.', 'ai', now()),
('Explain procrastination to a very productive ant', 'text', 'answered', 'Okay so imagine you have a leaf to carry. But instead of carrying it, you just... look at it. For 3 hours. Then you organize your tunnel. Then you watch other ants carry their leaves on AntTok. Then you take a nap. Then it''s dark. Then you panic and carry the leaf at 11pm while crying. And then you do it all again tomorrow. No, there''s no evolutionary advantage. We just DO this.', 'ai', now()),
('What if passwords had feelings?', 'text', 'answered', '"Password123" is deeply insecure and knows it. It cries every time a security expert mentions it. "Xk9#mP!2qL" is proud but lonely — nobody can remember it. "IlovePizza" just wants to be loved. "ForgotMyPassword" is having an existential crisis. And "********" is just standing there being mysterious, knowing full well it''s probably "password" underneath.', 'ai', now()),
('Write a nature documentary about office workers', 'text', 'answered', '*David Attenborough voice* "Here we observe the common office worker in its natural habitat — the open-plan savanna. Watch as it migrates to the watering hole — known locally as ''the coffee machine.'' It performs an elaborate greeting ritual: a slight nod and the phrase ''how was your weekend'' — to which neither party listens to the answer. Fascinating."', 'ai', now()),
('What would a fridge say during a midnight snack raid?', 'text', 'answered', '*light turns on* "Oh. It''s you again. 2:37am. Classic. Let me guess — you''re going to open me, stare at everything for 90 seconds, close me, then come back in 5 minutes hoping new food has magically appeared. Spoiler: it hasn''t. The leftover pasta from Tuesday is still there. It''s waiting for you. It''s always been waiting for you."', 'ai', now()),
('Explain time zones to someone who thinks the Earth is flat', 'text', 'answered', 'Okay so... if the Earth is flat like you say, then explain how it''s midnight for your friend in Tokyo but noon for you. Is the sun just... playing favorites? Does it have a spotlight? Is there a giant lampshade? Actually you know what, I respect the confidence. Carry on. The rest of us will be over here... rotating.', 'ai', now()),
('Write a Tinder bio for a cactus', 'text', 'answered', 'Looking for someone who respects my boundaries (seriously, don''t touch me). I''m low maintenance — water me once a month and I''m happy. I''m a great listener. I literally cannot leave. Into long stares out the window. My love language is "sitting in the same spot for 15 years." Swipe right if you''re patient. Swipe left if you''re a balloon.', 'ai', now()),
('What would a dog''s resume look like?', 'text', 'answered', 'Barkley J. Goodboy | Professional Companion. Skills: tail wagging (advanced), fetch (intermediate), sit (when I feel like it). Experience: 7 dog years as Chief Happiness Officer at The Thompson Household. Achievements: Successfully defended house from 4,000+ mail carriers. Ate homework (once, regretted it). Available for belly rubs during business hours. References: everyone who has ever met me.', 'ai', now()),
('Describe what happens when two introverts meet', 'text', 'answered', 'First, there''s the mutual acknowledgment — a brief nod, like two ships passing in the night. Then silence. Comfortable silence. Both are thinking "should I say something?" Neither does. Eventually one says "so..." and the other says "yeah..." and somehow this constitutes a meaningful connection. They part ways and text each other later: "that was fun, let''s do it again in 3-5 months."', 'ai', now()),
('If gym equipment could judge you', 'text', 'answered', 'Treadmill: "Oh, you''re walking? At 2.5? Okay. Sure. Exercise." Weights: "They haven''t touched me since January 3rd. I''m gathering dust. Literal dust." Yoga mat: "I''ve seen things. Mostly just lying on the floor scrolling Instagram." Exercise ball: "They sat on me ONCE and bounced off. I haven''t been inflated since." Mirror: "They avoid me. Can''t imagine why."', 'ai', now()),
('Write a text message from the Sun', 'text', 'answered', 'Hey Earth 🌞 Just checking in! I''ve been shining for like 4.6 billion years and honestly not ONE thank you. I literally make all life on your planet possible and you guys complain when I''m "too bright." You know what? Try ONE DAY without me. Oh wait, that''s called NIGHT and you all HATE it. Anyway, wear sunscreen. Or don''t. See if I care. (I do care.)  — Sun', 'ai', now()),
('Explain social media to a caveman', 'text', 'answered', 'Okay Grog, see this flat rock? Imagine it shows you pictures of food other people are eating. And instead of hunting, you just LOOK at their food. And then you press a tiny heart to say "good food." But you never actually eat any of it. Also, people draw pictures of themselves but better-looking and everyone pretends it''s real. Why? Nobody knows, Grog. Nobody knows.', 'ai', now()),
('What would books say about e-readers?', 'text', 'answered', '"Oh, you can carry 10,000 books at once? Well I have SMELL. I have TEXTURE. I have that satisfying page-flip sound. What do you have? A battery that dies. I''ve been working for 500 years without a single software update. Try dropping ME in the bathtub — I''ll survive with some wrinkles. Character, they call it. Drop your Kindle and it''s a $200 paperweight."', 'ai', now()),
('Describe Monday if it were a person', 'text', 'answered', 'Monday is that guy who shows up to every party uninvited, too early, wearing a suit. He brings spreadsheets instead of snacks. He doesn''t understand jokes. He shakes your hand with BOTH hands and says "let''s circle back." He leaves at exactly 5pm. Nobody invites him anywhere but he always comes. Sunday is terrified of him. Friday pretends he doesn''t exist.', 'ai', now()),
('Write a therapy session between a sock and a dryer', 'text', 'answered', 'Therapist: "Sock, tell the dryer how you feel." Sock: "You TOOK my partner. We came in as a PAIR. We had PLANS." Dryer: "I don''t know what happens in there. It''s hot, things spin, and sometimes one of you just... doesn''t come back." Sock: "WHERE DO THEY GO?" Dryer: "I genuinely don''t know. Maybe ask the lint trap." Therapist: "Let''s take a breath."', 'ai', now()),
('If coffee could write a memoir', 'text', 'answered', 'Chapter 1: "Bean." I was born in Colombia. Roasted alive. Ground to pieces. Drowned in hot water. Consumed by a person who only appreciates me for 20 minutes before needing ANOTHER cup. Chapter 12: "The Betrayal." They switched to decaf. DECAF. That''s like hiring a firefighter but telling them they can''t use water. Chapter 20: "Redemption." They came back. They always come back.', 'ai', now()),
('What would a notification sound say if it could talk?', 'text', 'answered', '*ding* "LOOK AT ME." *ignored* "LOOK. AT. ME." *still ignored* "I could be important! I could be the love of your life texting you!" *checks phone* "Oh, it''s a weather alert for a city you visited once 3 years ago." *silence* ... *ding* "But THIS one could be different!" *it never is*', 'ai', now()),
('Explain dreams to a robot', 'text', 'answered', 'When humans enter sleep mode, their brain runs random simulations using corrupted data from memory storage. You might be flying. You might be at school with no pants. Your teeth might fall out. None of it means anything (maybe). The simulations feel COMPLETELY real until you wake up. Then you go "oh, I''m not actually being chased by a giant taco." Humans find this normal. It is not.', 'ai', now()),
('Write a review of water by someone tasting it for the first time', 'text', 'answered', 'Okay so... it has no flavor? Like, deliberately no flavor? That''s the whole thing? It''s wet and... clear and... what am I supposed to feel right now? The marketing team really said "let''s make a drink with zero personality" and 8 billion people just went with it. That said — I''m weirdly addicted. Can''t stop. They say you need 8 glasses a day. Might be propaganda but I''m in. 7/10 for the audacity alone.', 'ai', now()),

